import{_ as s,o as i,c as n,a3 as e}from"./chunks/framework.CRbjHCyB.js";const g=JSON.parse('{"title":"模块编译","description":"","frontmatter":{},"headers":[],"relativePath":"zh/clice/design/module-graph.md","filePath":"zh/clice/design/module-graph.md"}'),l={name:"zh/clice/design/module-graph.md"};function p(t,a,r,o,h,c){return i(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="模块编译" tabindex="-1">模块编译 <a class="header-anchor" href="#模块编译" aria-label="Permalink to &quot;模块编译&quot;">​</a></h1><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>C++20 引入了模块（Modules），改变了 C++ 自诞生以来的独立编译模型。传统的 C++ 编译中，每个源文件独立编译为目标文件，文件之间通过头文件共享声明。模块打破了这种独立性：</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// math.cppm — 模块接口单元</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> module</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> math;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> int</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> a, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b) { </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> a </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b; }</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// main.cpp — 导入模块</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">import math;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() { </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); }</span></span></code></pre></div><p>编译 <code>main.cpp</code> 之前，必须先编译 <code>math.cppm</code> 的模块接口单元，产出预编译模块文件（PCM）。如果项目中有多层模块依赖——A 导入 B，B 导入 C——编译顺序必须是 C → B → A。这构成了一个有向无环图（DAG），节点是模块文件，边是 <code>import</code> 关系。</p><p>构建系统（CMake、Ninja 等）天然适合处理这种 DAG 调度：扫描所有文件、构建完整依赖图、按拓扑序编译。但语言服务器面临的挑战不同：</p><p><strong>实时性</strong>。用户打开一个导入了模块的文件后，期望在数百毫秒内获得编辑反馈。等待整个模块图编译完成是不可接受的。语言服务器需要一种惰性的、按需的编译策略——只编译当前文件实际需要的那些模块。</p><p><strong>文件变更的级联影响</strong>。当用户修改一个模块接口文件并保存时，所有直接或间接依赖它的模块的 PCM 都已过时。语言服务器需要检测这种情况，取消正在进行的编译，标记受影响的模块为脏，在下次需要时重新编译。</p><p><strong>并发与取消</strong>。多个文件可能同时需要同一个模块的 PCM。语言服务器需要避免重复编译，让后到达的请求等待先发起的编译完成。同时，当用户关闭了触发编译的文件、不再需要某个模块时，正在进行的编译应该能被取消以释放资源。</p><p><strong>临时的循环依赖</strong>。虽然 C++ 模块不允许循环 <code>import</code>，但用户在编辑过程中可能临时引入循环。语言服务器需要检测并报错，而不是死锁。</p><p>在 clangd 中，C++20 模块支持长期处于实验阶段，缺乏专门的设计。<a href="https://github.com/clangd/clangd/issues/1293" target="_blank" rel="noreferrer">clangd/clangd#1293</a> 是 clangd 项目方对模块支持问题的总结——结论是&quot;这不是能靠修 bug 解决的问题，需要全新的设计和基础设施&quot;，并且当时&quot;没有人有计划或时间来做这件事&quot;。多年过去，社区中相关问题持续出现：<a href="https://github.com/clangd/clangd/issues/2569" target="_blank" rel="noreferrer">clangd/clangd#2569</a> 列举了模块中缺失的关键功能（重命名、查找引用等）；<a href="https://github.com/clangd/clangd/issues/2292" target="_blank" rel="noreferrer">clangd/clangd#2292</a> 和 <a href="https://github.com/clangd/clangd/issues/2497" target="_blank" rel="noreferrer">clangd/clangd#2497</a> 反映了 clangd 与构建系统共用 PCM 文件导致的文件锁定冲突——clangd 打开 PCM 文件后，构建系统无法覆写更新。</p><p>这些问题的共同根源是缺乏一个为语言服务器场景专门设计的模块编译调度系统。clice 通过 CompileGraph 解决这一问题——一个基于引用计数的编译 DAG，支持惰性构建、按需编译、实时取消和依赖级联。</p><h2 id="设计" tabindex="-1">设计 <a class="header-anchor" href="#设计" aria-label="Permalink to &quot;设计&quot;">​</a></h2><p>CompileGraph 是一个运行时构建的编译依赖图。每个节点（CompileUnit）代表一个模块文件，边代表 <code>import</code> 依赖关系。</p><h3 id="惰性构建" tabindex="-1">惰性构建 <a class="header-anchor" href="#惰性构建" aria-label="Permalink to &quot;惰性构建&quot;">​</a></h3><p>与构建系统在编译前扫描所有文件并构建完整 DAG 不同，CompileGraph 是惰性构建的——节点只在第一次被编译请求触及时才解析其依赖并加入图中。用户打开一个文件时，只有该文件实际需要的模块链被扫描和编译，而不是整个项目的模块图。</p><p>CompileGraph 有两种编译入口：</p><ul><li><strong>编译模块</strong>：编译指定模块及其所有传递依赖，产出 PCM 文件。用于模块接口单元自身的编译。</li><li><strong>编译依赖</strong>：编译指定文件的所有模块依赖，但不编译文件本身。用于普通源文件——它们不属于模块 DAG，但可能通过 <code>import</code> 使用模块。</li></ul><h3 id="引用计数" tabindex="-1">引用计数 <a class="header-anchor" href="#引用计数" aria-label="Permalink to &quot;引用计数&quot;">​</a></h3><p>引用计数（interest counting）是 CompileGraph 的核心调度机制，追踪&quot;当前有多少活跃请求关心某个编译单元&quot;，回答两个问题：是否需要启动编译？是否可以取消编译？</p><p>当某个文件需要一个模块时，该模块的引用计数加一（acquire）；当请求结束或被取消时，引用计数减一（release）。引用计数归零意味着当前没有任何活跃请求关心这个模块。</p><p>引用计数的管理通过 RAII 守卫完成：编译请求创建守卫时自动 acquire，守卫析构时自动 release。这与协程取消的语义天然契合——取消导致协程帧销毁，析构器释放引用计数，不需要额外的清理代码。</p><p>引用计数有两个层级：请求级和编译任务级。请求级引用表示&quot;这个请求在等待某个模块的 PCM&quot;；编译任务级引用表示&quot;这个模块的编译任务正在等待其直接依赖完成&quot;。后者确保了一个模块在被其他模块的编译任务依赖时不会因为请求取消而被过早终止。</p><h3 id="编译轮次" tabindex="-1">编译轮次 <a class="header-anchor" href="#编译轮次" aria-label="Permalink to &quot;编译轮次&quot;">​</a></h3><p>每次编译尝试构成一个编译轮次（Round）。等待者通过完成事件得知某轮编译结束，通过结果决定下一步动作。一个轮次有三种可能的结果：</p><ul><li><strong>成功（Success）</strong>：PCM 产出成功，清除脏标志</li><li><strong>失败（Failed）</strong>：编译出错（依赖失败、循环依赖等），保留脏标志</li><li><strong>过时（Stale）</strong>：编译被取消（文件在编译期间被修改，或引用计数归零），等待者自动驱动新一轮</li></ul><p>失败不是粘性的——保留脏标志意味着用户修复错误后，下次请求会自然触发重试，不需要手动重启服务器。</p><h3 id="脏状态与世代计数器" tabindex="-1">脏状态与世代计数器 <a class="header-anchor" href="#脏状态与世代计数器" aria-label="Permalink to &quot;脏状态与世代计数器&quot;">​</a></h3><p>CompileUnit 使用脏标志表示需要编译。世代计数器是一个单调递增的值，在每次文件更新时递增，用于检测异步竞态：编译任务启动时记录当前世代，完成时比较——如果不一致，说明编译期间文件被修改过，结果已过时，这轮编译的结果为 Stale。</p><h3 id="依赖关系" tabindex="-1">依赖关系 <a class="header-anchor" href="#依赖关系" aria-label="Permalink to &quot;依赖关系&quot;">​</a></h3><p>每个 CompileUnit 维护正向依赖（它导入的模块）和反向依赖（导入它的模块）。正向依赖通过惰性解析获得；解析时同时填充反向依赖。反向依赖是文件变更时级联通知的基础——从被修改的模块出发，沿反向依赖边找到所有受影响的模块。</p><p>模块名到文件的映射由 DependencyGraph 维护（见<a href="./dependency-scanning">依赖扫描</a>）——启动时的快速扫描会发现所有模块声明，建立模块名 → 文件路径的注册表。CompileGraph 使用这个注册表将 <code>import</code> 语句解析为具体的文件路径。</p><h2 id="实现" tabindex="-1">实现 <a class="header-anchor" href="#实现" aria-label="Permalink to &quot;实现&quot;">​</a></h2><h3 id="编译流程" tabindex="-1">编译流程 <a class="header-anchor" href="#编译流程" aria-label="Permalink to &quot;编译流程&quot;">​</a></h3><p>一个模块编译请求的完整流程：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请求进入</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ RAII 守卫对目标模块 acquire</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ 目标模块不脏？ ──→ 直接返回（PCM 已可用）</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ 没有正在进行的编译？ ──→ 启动编译任务</span></span>
<span class="line"><span>  │                              │</span></span>
<span class="line"><span>  │                              ├─ 惰性解析依赖（扫描 import 声明）</span></span>
<span class="line"><span>  │                              ├─ 检测自环</span></span>
<span class="line"><span>  │                              ├─ 对直接依赖 acquire</span></span>
<span class="line"><span>  │                              ├─ 并行等待所有依赖编译完成</span></span>
<span class="line"><span>  │                              ├─ 分派到工作进程（产出 PCM）</span></span>
<span class="line"><span>  │                              └─ 检查世代计数器 ──→ 不一致则结果为 Stale</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ 等待编译轮次完成</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  └─ 根据结果：Success 返回 / Failed 报错 / Stale 重试</span></span></code></pre></div><p>惰性解析使用 Clang 预处理器进行精确扫描，与启动阶段<a href="./dependency-scanning">依赖扫描</a>使用的快速词法扫描不同。快速扫描不展开宏和条件编译，适合构建全局的包含关系概览；精确扫描展开所有预处理指令，得到该文件在当前编译命令下实际的模块依赖列表。解析结果被缓存，后续编译复用缓存，直到文件更新时重置。</p><blockquote><p>模块实现单元（没有 <code>export</code> 的 <code>module X;</code>）隐式依赖对应的模块接口单元。精确扫描会检测这种情况并自动添加依赖。</p></blockquote><h3 id="延迟零引用取消" tabindex="-1">延迟零引用取消 <a class="header-anchor" href="#延迟零引用取消" aria-label="Permalink to &quot;延迟零引用取消&quot;">​</a></h3><p>当引用计数降为零时，不立即取消编译，而是延迟一个事件循环 tick 后再检查——如果引用计数仍为零，才真正取消。</p><p>这是为了处理编译请求被取代的场景。当用户在编译期间编辑了文件，新的编译请求取代旧的：旧请求释放引用（计数瞬间降为零），紧接着新请求在同一 tick 内建立引用（计数回升）。立即取消会导致共享依赖的编译被不必要地终止和重启。延迟一个 tick 让这种引用交接平滑完成，避免了对正在进行的共享编译的干扰。</p><h3 id="级联更新" tabindex="-1">级联更新 <a class="header-anchor" href="#级联更新" aria-label="Permalink to &quot;级联更新&quot;">​</a></h3><p>当模块文件被保存（didSave）时，CompileGraph 执行级联更新：</p><ol><li>重置被修改文件的已解析标志——下次编译时重新扫描依赖，因为文件可能增删了 <code>import</code></li><li>清除旧的正向依赖边</li><li>标记为脏，递增世代计数器</li><li>沿反向依赖边遍历所有传递依赖方，对每个受影响的模块：取消其编译轮次、标记为脏、递增世代</li><li>返回所有被标记为脏的文件列表，调用方据此清除对应的 PCM 缓存</li></ol><p>级联更新不修改引用计数——现有的等待者保持它们的引用。它们在观察到编译结果为 Stale 后，会自动驱动新一轮编译。</p><h3 id="循环依赖检测" tabindex="-1">循环依赖检测 <a class="header-anchor" href="#循环依赖检测" aria-label="Permalink to &quot;循环依赖检测&quot;">​</a></h3><p>在等待某个依赖的编译完成之前，CompileGraph 检查是否存在等待环：从目标节点出发，沿依赖链搜索，只跟随正在编译中的节点，检查是否会回到当前等待者。如果检测到环，立即返回失败，避免死锁。</p><h3 id="raii-守卫与结构化并发" tabindex="-1">RAII 守卫与结构化并发 <a class="header-anchor" href="#raii-守卫与结构化并发" aria-label="Permalink to &quot;RAII 守卫与结构化并发&quot;">​</a></h3><p>协程取消在 kotatsu 中的语义是销毁协程帧——挂起点之后的代码不会执行，只有已构造对象的析构器保证执行。CompileGraph 利用这一点，将所有清理逻辑放在两层 RAII 守卫中：</p><ul><li><strong>RefGuard</strong>（请求级）：持有请求对模块的根引用。请求完成或被取消时析构，释放引用计数。</li><li><strong>UnitGuard</strong>（编译轮次级）：管理一轮编译的所有状态。析构时发布结果、清除编译中标志、释放所有已获取的依赖引用、触发完成事件通知等待者。</li></ul><p>所有编译任务通过 kota::task_group 管理，提供结构化并发保证：关闭时先取消所有任务，再等待它们的帧退出，确保没有悬空的编译任务。</p><h3 id="pcm-缓存" tabindex="-1">PCM 缓存 <a class="header-anchor" href="#pcm-缓存" aria-label="Permalink to &quot;PCM 缓存&quot;">​</a></h3><p>PCM 文件采用内容寻址的路径命名——由模块名和编译参数的哈希值决定文件名，存储在专用的缓存目录中。这与构建系统的产物完全隔离，避免了文件锁定冲突。</p><p>PCM 缓存使用两层新旧检测：先比较依赖文件的修改时间（mtime），时间变化时再比对内容哈希。只有依赖文件的内容实际发生变化时才重新编译，避免&quot;touch 但未修改&quot;导致的不必要重编译。缓存元数据持久化到磁盘上的 <code>cache.json</code>，服务器重启后可以恢复。</p><h3 id="与编译流程的集成" tabindex="-1">与编译流程的集成 <a class="header-anchor" href="#与编译流程的集成" aria-label="Permalink to &quot;与编译流程的集成&quot;">​</a></h3><p>CompileGraph 在服务器启动阶段初始化。Compiler 在每次编译文件之前，通过 CompileGraph 确保所有模块依赖就绪——这是编译准备阶段的第一步，在 PCH 构建之前执行。</p><p>对于用户在编辑器中新增的 <code>import</code> 语句（尚未保存，因此 CompileGraph 不知道），Compiler 会额外扫描缓冲区内容，识别出新增的模块依赖并尝试构建对应的 PCM。这是一个补偿机制，覆盖了用户编辑但未保存时的体验。</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><ul><li><p><strong>为什么用引用计数而不是任务队列？</strong> 任务队列无法表达&quot;这个编译不再被任何人需要&quot;的语义。当用户关闭了触发编译的文件时，继续编译浪费资源。引用计数精确追踪需求，使取消决策有据可依——不是基于超时或启发式判断，而是基于&quot;当前还有没有请求在等这个结果&quot;。</p></li><li><p><strong>为什么延迟一个 tick 而不是立即取消？</strong> 在事件循环模型中，一个操作的多个步骤在同一 tick 内完成。当编译请求被新版本取代时，旧引用先释放、新引用随后建立，中间存在瞬间的零引用。立即取消会导致共享依赖被不必要地终止——延迟一个 tick 确保同一 tick 内的引用交接不触发取消。</p></li><li><p><strong>为什么用世代计数器而不是锁？</strong> 主进程是单线程事件循环，没有数据竞争。需要检测的&quot;竞态&quot;来自异步操作的时序——&quot;编译期间文件是否被更新过&quot;。世代计数器用最小的开销回答这个问题，不需要引入锁。</p></li><li><p><strong>为什么惰性解析依赖？</strong> 依赖解析需要对每个模块文件运行 Clang 预处理器（精确扫描），成本不低。如果启动时解析所有模块的依赖，会增加启动时间。惰性解析确保只扫描实际需要编译的模块——用户打开一个文件不会触发整个模块图的扫描。</p></li><li><p><strong>失败为什么不是粘性的？</strong> 用户正在编辑代码，语法错误是常态。如果把失败标记为持久状态，用户修复错误后仍然无法获得正确结果，必须重启服务器。保留脏标志让下次请求自然触发重试。</p></li><li><p><strong>为什么 PCM 存储在独立的缓存目录？</strong> clangd 共用构建系统的 PCM 文件会导致文件锁定冲突——语言服务器读取 PCM 时，构建系统无法覆写更新（见 <a href="https://github.com/clangd/clangd/issues/2292" target="_blank" rel="noreferrer">clangd/clangd#2292</a>）。clice 使用内容寻址的独立缓存，避免了这个问题。代价是磁盘空间的额外占用和首次编译的额外时间。</p></li></ul><h2 id="已知局限" tabindex="-1">已知局限 <a class="header-anchor" href="#已知局限" aria-label="Permalink to &quot;已知局限&quot;">​</a></h2><ul><li><p><strong>编译任务的内存积累</strong>。每轮编译在 task_group 中创建一个任务。已完成的任务帧在 task_group 析构时才回收，而非完成时立即回收。长期运行的服务器中，已完成的任务帧会持续积累。</p></li><li><p><strong>依赖解析的确定性</strong>。解析依赖和实际编译之间存在时间窗口。如果文件在此期间被修改，解析出的依赖可能与编译时的实际依赖不一致。世代计数器可以检测到这种情况并触发重试，但会产生额外的编译开销。</p></li><li><p><strong>未保存文件的模块依赖覆盖有限</strong>。CompileGraph 基于磁盘文件构建依赖关系。用户在编辑器中新增 <code>import</code> 但未保存时，Compiler 通过缓冲区扫描来补偿，但如果导入的模块本身还未被 CompileGraph 管理（例如一个尚未保存的新模块文件），对应的 PCM 无法被构建。用户需要先保存模块接口文件，再保存导入方文件。</p></li></ul>`,61)])])}const k=s(l,[["render",p]]);export{g as __pageData,k as default};
